import type { ApiResponse, TicketDto, TestimonialDto, OfferDto } from "./types";

async function jsonGet<T>(url: string, init?: RequestInit): Promise<ApiResponse<T>> {
  const res = await fetch(url, { cache: "no-store", ...init });
  const json = await res.json();
  return json as ApiResponse<T>;
}

export async function fetchTicketsApi(): Promise<TicketDto[]> {
  const res = await jsonGet<TicketDto[]>("/api/tickets");
  if (res.success) {
    return (res.data as any[]).map((t: any) => ({
      id: t.id,
      name: t.name,
      description: t.description || "",
      slug: t.slug,
      customerPrice: Number(t.customerPrice ?? t.price ?? 0),
      agentPrice: Number(t.agentPrice ?? 0),
    }));
  }
  throw new Error(res.message || "Failed to load tickets");
}

export async function fetchTestimonialsApi(featured?: boolean): Promise<TestimonialDto[]> {
  const qs = featured ? "?featured=true" : "";
  const res = await jsonGet<TestimonialDto[]>(`/api/testimonials${qs}`);
  if (res.success) {
    return (res.data as any[]).map((t: any) => ({
      id: t.id,
      name: t.name,
      rating: Number(t.rating) || 0,
      content: t.content || "",
      visitDate: t?.visitDate
        ? typeof t.visitDate === "string"
          ? t.visitDate.split("T")[0]
          : new Date(t.visitDate).toISOString().split("T")[0]
        : "",
      createdAt: t.createdAt,
    }));
  }
  throw new Error(res.message || "Failed to load testimonials");
}

export async function fetchOffersApi(): Promise<OfferDto[]> {
  const res = await jsonGet<OfferDto[]>(`/api/offers`);
  if (res.success) {
    return res.data as any;
  }
  throw new Error(res.message || "Failed to load offers");
}

